# Install the plugin
npm install --save-dev eslint-plugin-react-hooks

# ESLint config (eslint.config.js — flat config, ESLint 9+)
import reactHooks from 'eslint-plugin-react-hooks';

export default [
  {
    plugins: { 'react-hooks': reactHooks },
    rules: {
      'react-hooks/rules-of-hooks': 'error',
      'react-hooks/exhaustive-deps': 'warn',  // or 'error'
    },
  },
];

# Legacy .eslintrc format
# { "extends": ["plugin:react-hooks/recommended"] }

// ✗ ESLint warning: 'userId' is missing from deps
useEffect(() => {
  fetchUser(userId); // userId is reactive — must be a dep
}, []); // empty array is incorrect here

// ✓ Fix: add userId
useEffect(() => {
  fetchUser(userId);
}, [userId]);

// ESLint may warn: 'setCount' is unnecessarily in deps
// (though the rule is generally permissive about stable values)
useEffect(() => {
  setCount(0);
}, [setCount]); // setCount is stable — technically fine but redundant

// ✓ More precise:
useEffect(() => {
  setCount(0);
}, []);

// Note: the rule does NOT warn about setCount in the array;
// it only warns about missing values, not stable values that are listed.

// ESLint warning about over-broad dep:
// 'The 'options' object makes the dependencies change on every render.
//  Move it inside useEffect or wrap it in useMemo.'
useEffect(() => {
  connect(options);
}, [options]); // options is likely a new object each render

// ✓ Fix: destructure
useEffect(() => {
  connect({ host: options.host, port: options.port });
}, [options.host, options.port]);

// Before
useEffect(() => {
  document.title = `${user.name} - ${appName}`;
}, [user.name]); // ← ESLint: 'appName' is missing

// After
useEffect(() => {
  document.title = `${user.name} - ${appName}`;
}, [user.name, appName]);

// ✗ Incorrect: silencing the lint rule
useEffect(() => {
  initAnalytics(userId); // userId only needed at init time
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, []);

// ✓ Correct: read the latest value via a ref
const userIdRef = useRef(userId);
useEffect(() => {
  initAnalytics(userIdRef.current); // reads current value without being reactive
}, []); // genuinely no deps — userIdRef is stable

// Alternative: if init is idempotent, just add userId as dep
useEffect(() => {
  initAnalytics(userId);
}, [userId]); // re-inits if userId changes — may be correct behaviour

// ✗ ESLint: 'handleData' is missing from deps
function Component({ onEvent }) {
  function handleData(data) {
    onEvent(data);
  }

  useEffect(() => {
    stream.subscribe(handleData);
    return () => stream.unsubscribe(handleData);
  }, []);
}

// ✓ Fix A: move handleData inside the effect
useEffect(() => {
  function handleData(data) { onEvent(data); }
  stream.subscribe(handleData);
  return () => stream.unsubscribe(handleData);
}, [onEvent]);

// ✓ Fix B: useCallback + add to deps
const handleData = useCallback((data) => onEvent(data), [onEvent]);
useEffect(() => {
  stream.subscribe(handleData);
  return () => stream.unsubscribe(handleData);
}, [handleData]);

// Only suppress when you've confirmed:
// 1. The effect intentionally captures an initial value
// 2. Re-running on dep change would break behaviour
// 3. You've read the exhaustive-deps docs on this pattern

useEffect(() => {
  // 'initialCount' is intentionally read once at mount; we don't
  // want to re-run if it changes (it's a stable initial prop).
  counter.init(initialCount);
  // eslint-disable-next-line react-hooks/exhaustive-deps
}, []);

// Every disable comment must have a justification comment above it.
// Unexplained disables in code review should be treated as a red flag.

// useCallback: same rule applies
const save = useCallback(() => {
  api.save(userId, data);
}, [userId]); // ESLint: 'data' is missing

// ✓ Fix
const save = useCallback(() => {
  api.save(userId, data);
}, [userId, data]);

// useMemo: same rule applies
const processed = useMemo(() => {
  return transform(items, config);
}, [items]); // ESLint: 'config' is missing

// ✓ Fix
const processed = useMemo(() => {
  return transform(items, config);
}, [items, config]);

// eslint.config.js
rules: {
  'react-hooks/exhaustive-deps': ['warn', {
    additionalHooks: '(useMyEffect|useInterval|useEventListener)',
  }],
}

// Now the rule also checks custom hooks matching the regex:
useInterval(() => {
  update(count); // ESLint: 'count' is missing from useInterval deps
}, [1000]); // delay is dep, count is not listed

# package.json script
{
  "scripts": {
    "lint": "eslint src --ext .js,.jsx,.ts,.tsx",
    "lint:ci": "eslint src --ext .js,.jsx,.ts,.tsx --max-warnings 0"
  }
}

# --max-warnings 0 treats warnings as errors — use this in CI
# to prevent merging code with exhaustive-deps violations.

// AST analysis example:
useEffect(() => {
  //          ↓ declared outside component — stable — no dep needed
  const url = API_BASE_URL + '/users/' + userId;
  //                                      ↑ declared in component — reactive — must be dep
  fetch(url).then(r => r.json()).then(data => {
    setUser(data);
    //  ↑ state setter — stable by React guarantee — not needed in deps
  });
}, [userId]); // ✓ correct — only reactive value is userId

// ESLint warns about 'user' not just 'user.id'
useEffect(() => {
  fetchPosts(user.id); // rule sees 'user' as the dep
}, [user.id]); // ← ESLint may warn: use 'user' or destructure

// ✓ Option A: list user.id (ESLint accepts property access in some versions)
useEffect(() => {
  fetchPosts(user.id);
}, [user.id]); // accepted by newer versions of the rule

// ✓ Option B: destructure before the effect
const { id: userId } = user;
useEffect(() => {
  fetchPosts(userId);
}, [userId]); // clear primitive dep

// Pattern: extract to helper function
// ✗ fetchWithConfig uses 'config' object — unstable ref
useEffect(() => {
  fetchWithConfig(config);
}, [config]); // config is new every render

// ✓ Extract config fields and pass as args
useEffect(() => {
  fetchWithArgs(config.url, config.method, config.headers);
}, [config.url, config.method, config.headers]);

// Or: build config inside effect
useEffect(() => {
  const opts = { url, method, headers }; // built from stable primitives
  fetchWithConfig(opts);
}, [url, method, headers]);

// TypeScript — rule behaves identically
function UserCard({ userId }: { userId: string }) {
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    fetchUser(userId).then((data: User) => setUser(data));
  }, [userId]); // same rule: userId must be a dep
}
